+    fn graph_search_matches(&self) -> Vec<usize> {
+        let query = self.graph_search_query.trim().to_ascii_lowercase();
+        if query.is_empty() {
+            return Vec::new();
+        }
+        self.visible_issue_indices()
+            .into_iter()
